import Box from '@mui/material/Box';
import Typography from '@mui/material/Typography';
import Grid from '@mui/material/Unstable_Grid2';
import {GatsbyImage, getImage} from 'gatsby-plugin-image';

import Link from '@mui/material/Link';
import Divider from '@mui/material/Divider';
import * as React from 'react';
import {graphql, useStaticQuery} from 'gatsby';
import Seo from '../components/seo';
import Breadcrumbs from '@mui/material/Breadcrumbs';
import Paper from '@mui/material/Paper';
import Layout from '../components/layout';

const Desc = ({desc}) => {
  let html = desc.data.childMarkdownRemark.html;
  desc.medias.forEach(item => {
    const reg = new RegExp(`(<img src="${item.src}".*?">)`, 'g');
    html = html.replaceAll(reg,
        `<div class="image-wrapper"><img src="${item.localFile.publicURL}"></div>`);
  });
  return (<Grid md={12} xs={12} sx={{mx: {md: 2, xs: 1}}} className="markdown"
                dangerouslySetInnerHTML={{__html: html}}></Grid>);
};

const Contact = () => {

  const {
    strapiCorporateSell,
  } = useStaticQuery(graphql`
  query ContactQuery {
  strapiCorporateSell {
    desc {
      data {
        childMarkdownRemark {
          html
        }
      }
      medias {
        src
        localFile {
          publicURL
        }
      }
    }
  }
}`);
  const desc = strapiCorporateSell.desc;

  return (
      <Layout>
        <Box sx={{mt: 1}}>
          <Paper elevation={2} sx={{mr: 2, ml: 2}}>
            <Breadcrumbs sx={{pt: 2, pb: 4, pl: 2, pr: 2}}
                         aria-label="breadcrumb">
              <Link underline="hover" color="inherit" href="/">
                首页
              </Link>
              <Typography color="text.primary">联系方式</Typography>
            </Breadcrumbs>
            <Box sx={{flexGrow: 1, pt: 2, pb: 2, ml: 2, mr: 2}}>
              <Grid container display="flex" justifyContent="center"
                    alignItems="center" spacing={0.5}
                    columns={{xs: 4, sm: 8, md: 12}}>
               <Desc desc={desc}></Desc>
              </Grid>


            </Box>
          </Paper>
        </Box>
      </Layout>

  );
};

export const Head = () => <Seo title="联系方式"/>;
export default Contact;
